import { GoogleGenAI, Type, GenerateContentResponse, Modality } from "@google/genai";
import type { StoryFormState, StoryGenerationResponse, ScriptFormState, ScenePrompt, ArticleData, AdImageFormState, AdSuggestion, AdImageFile, AdImageRole } from '../types';

const GEMINI_MODEL = "gemini-2.5-flash";
const GEMINI_PRO_MODEL = "gemini-3-pro-preview";
const IMAGE_GEN_MODEL = "imagen-4.0-generate-001";
const IMAGE_EDIT_MODEL = "gemini-2.5-flash-image";
const VEO_MODEL = "veo-3.1-fast-generate-preview";

// Khởi tạo client một lần duy nhất ở cấp độ module để tái sử dụng.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });


/**
 * Một hàm trợ giúp bao bọc lệnh gọi API Gemini với cơ chế thử lại.
 * Nó sử dụng thuật toán exponential backoff với jitter để xử lý lỗi giới hạn tốc độ (429).
 * @param params Các tham số cho lệnh gọi generateContent.
 * @param maxRetries Số lần thử lại tối đa.
 * @param initialDelay Độ trễ ban đầu tính bằng mili giây trước lần thử lại đầu tiên.
 * @returns Một promise phân giải thành phản hồi của API.
 */
async function generateContentWithRetry(
    params: { model: string; contents: any; config?: any; },
    maxRetries = 3,
    initialDelay = 2000 // Bắt đầu với độ trễ 2 giây
): Promise<GenerateContentResponse> {
    let attempt = 0;
    while (attempt < maxRetries) {
        try {
            const response = await ai.models.generateContent(params);
            return response;
        } catch (error) {
            attempt++;
            const isRetryable = error instanceof Error && (
                error.message.includes('429') ||
                error.message.toLowerCase().includes('rate limit') ||
                error.message.includes('500') ||
                error.message.toLowerCase().includes('xhr error')
            );
            if (isRetryable && attempt < maxRetries) {
                const delay = initialDelay * (2 ** (attempt - 1)) + Math.random() * 1000;
                console.warn(`Lệnh gọi API thất bại, thử lại sau ${Math.round(delay / 1000)}s... (Lần thử ${attempt}/${maxRetries})`);
                await new Promise(resolve => setTimeout(resolve, delay));
            } else {
                console.error(`Lệnh gọi API thất bại sau ${attempt} lần thử.`, error);
                throw error;
            }
        }
    }
    throw new Error("Lệnh gọi API thất bại sau khi đạt đến số lần thử lại tối đa.");
}

/**
 * Một hàm trợ giúp bao bọc lệnh gọi API generateImages với cơ chế thử lại.
 * @param params Các tham số cho lệnh gọi generateImages.
 * @param maxRetries Số lần thử lại tối đa.
 * @param initialDelay Độ trễ ban đầu tính bằng mili giây.
 * @returns Một promise phân giải thành phản hồi của API.
 */
async function generateImagesWithRetry(
    params: { model: string; prompt: string; config?: any; },
    maxRetries = 3,
    initialDelay = 2000
): Promise<{ generatedImages: { image: { imageBytes: string } }[] }> {
    let attempt = 0;
    while (attempt < maxRetries) {
        try {
            const response = await ai.models.generateImages(params);
            return response;
        } catch (error) {
            attempt++;
            const isRetryable = error instanceof Error && (
                error.message.includes('429') ||
                error.message.toLowerCase().includes('rate limit') ||
                error.message.includes('500') ||
                error.message.toLowerCase().includes('xhr error')
            );

            if (isRetryable && attempt < maxRetries) {
                const delay = initialDelay * (2 ** (attempt - 1)) + Math.random() * 1000;
                console.warn(`Lệnh gọi API generateImages thất bại, thử lại sau ${Math.round(delay / 1000)}s... (Lần thử ${attempt}/${maxRetries})`);
                await new Promise(resolve => setTimeout(resolve, delay));
            } else {
                console.error(`Lệnh gọi API generateImages thất bại sau ${attempt} lần thử.`, error);
                throw error;
            }
        }
    }
    throw new Error("Lệnh gọi API generateImages thất bại sau khi đạt đến số lần thử lại tối đa.");
}


/**
 * Trình xử lý lỗi tập trung cho các lệnh gọi API Gemini.
 * @param error Đối tượng lỗi đã bắt được.
 * @param context Một chuỗi mô tả ngữ cảnh của lệnh gọi API (ví dụ: "tạo câu chuyện").
 * @returns Một đối tượng Error mới với thông báo thân thiện với người dùng.
 */
function handleGeminiError(error: unknown, context: string): Error {
    console.error(`Lỗi trong lúc gọi API Gemini (${context}):`, error);
    let errorMessage = `Lỗi khi ${context}. Vui lòng thử lại.`;

    if (error instanceof Error) {
        const errorMsgLower = error.message.toLowerCase();
        if (errorMsgLower.includes('quota') || errorMsgLower.includes('resource_exhausted') || errorMsgLower.includes('429')) {
             errorMessage = "Lỗi: Hạn ngạch API đã hết. Vui lòng kiểm tra gói dịch vụ của bạn hoặc thử lại sau khi hạn ngạch được làm mới.";
        } else if (errorMsgLower.includes('api key not valid') || errorMsgLower.includes('requested entity was not found')) {
            errorMessage = "Lỗi: API Key không hợp lệ hoặc không được tìm thấy. Vui lòng chọn lại API Key hợp lệ và thử lại.";
        } else if (errorMsgLower.includes('json')) {
            errorMessage = `Lỗi khi phân tích phản hồi ${context}. Phản hồi không phải là JSON hợp lệ.`;
        } else if (errorMsgLower.includes('safety')) {
            errorMessage = "Nội dung yêu cầu đã bị chặn vì lý do an toàn. Vui lòng thử lại với một chủ đề khác.";
        } else {
             errorMessage = `Lỗi từ Gemini: ${error.message}`;
        }
    }
    return new Error(errorMessage);
}

const parseJsonResponse = <T>(responseText: string, context: string): T => {
    try {
        const parsedData = JSON.parse(responseText.trim());
        return parsedData as T;
    } catch (e) {
        throw new Error(`Phản hồi từ AI (${context}) không có cấu trúc JSON hợp lệ.`);
    }
};

/**
 * Tạo ra một câu chuyện chỉ có văn bản với một hồ sơ giọng đọc được đề xuất.
 */
export async function generateStory(formState: StoryFormState, context: string): Promise<StoryGenerationResponse> {
    const { theme, age, genre, style } = formState;

    const prompt = `
Viết một chương truyện tiếng Việt.
${context
? `Yêu cầu: Viết chương TIẾP THEO, duy trì tính nhất quán.
Ngữ cảnh (Các chương trước):\n${context}`
: `Yêu cầu: Viết chương ĐẦU TIÊN của truyện mới.
Thông tin truyện:
- Chủ đề: "${theme}"
- Thể loại: "${genre.join(', ')}"
- Đối tượng: "${age}"
- Phong cách: "${style.join(', ')}"`
}

JSON Output:
- story.synopsis: ${context ? '""' : 'Tóm tắt ngắn gọn toàn bộ câu chuyện.'}
- story.storyText: Nội dung của CHỈ chương MỚI, có ghi nhãn chương (ví dụ: "Chương 1").
- story.voiceProfile: ${context ? 'Đối tượng JSON mặc định.' : 'Hồ sơ giọng đọc chi tiết.'}
`;

    try {
        const response = await generateContentWithRetry({
            model: GEMINI_MODEL,
            contents: prompt,
            config: {
                systemInstruction: "Bạn là một nhà văn chuyên nghiệp, sáng tạo, chuyên viết truyện ngắn và tiểu thuyết. Hãy viết với văn phong tự nhiên, giàu hình ảnh và cảm xúc, phù hợp với lứa tuổi độc giả.",
                thinkingConfig: { thinkingBudget: 4096 },
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: { story: { type: Type.OBJECT, properties: { synopsis: { type: Type.STRING }, storyText: { type: Type.STRING }, voiceProfile: { type: Type.OBJECT, properties: { description: { type: Type.STRING }, gender: { type: Type.STRING }, tone: { type: Type.STRING }, speed: { type: Type.STRING }, readingNotes: { type: Type.STRING } } } } } },
                },
            }
        });

        const parsedData = parseJsonResponse<StoryGenerationResponse>(response.text, "tạo truyện");
        if (!parsedData?.story?.storyText || !parsedData?.story?.voiceProfile) {
             throw new Error("Phản hồi từ AI không có cấu trúc hợp lệ.");
        }
        return parsedData;
    } catch (error) {
        throw handleGeminiError(error, "tạo câu chuyện");
    }
}

/**
 * Tạo bài báo song ngữ từ danh sách URL.
 */
export async function generateArticleFromUrls(urls: string[]): Promise<ArticleData> {
    const prompt = `
Nhiệm vụ: Dựa trên nội dung từ các URL được cung cấp, hãy thực hiện các công việc sau:
1. Tổng hợp thông tin và viết một bài báo gốc, mạch lạc bằng tiếng Việt.
2. Dịch chính xác bài báo đó sang tiếng Anh.
3. Tạo tóm tắt cho mạng xã hội cho cả hai ngôn ngữ.
4. Tạo một prompt tạo ảnh phù hợp.

URLs để phân tích:\n${urls.join('\n')}

QUY TẮC QUAN TRỌNG:
1. Bài viết phải là nội dung gốc được tổng hợp, không sao chép trực tiếp.
2. 'imagePrompt' phải bằng tiếng Anh, mô tả một hình ảnh có thể minh họa cho chủ đề chính của bài báo.

JSON Output:
- vietnameseTitle: (Bắt buộc) Tiêu đề hấp dẫn cho bài báo tiếng Việt.
- englishTitle: (Bắt buộc) Bản dịch tiếng Anh của tiêu đề trên.
- vietnameseArticle: (Bắt buộc) Toàn bộ nội dung bài báo bằng tiếng Việt.
- englishArticle: (Bắt buộc) Toàn bộ nội dung bài báo bằng tiếng Anh.
- socialMediaSummaryVI: (Bắt buộc) Tóm tắt ngắn gọn (dưới 280 ký tự) bằng tiếng Việt.
- socialMediaSummaryEN: (Bắt buộc) Tóm tắt ngắn gọn (dưới 280 ký tự) bằng tiếng Anh.
- imagePrompt: (Bắt buộc) Prompt chi tiết bằng tiếng Anh để tạo ảnh minh họa cho bài báo.
`;
    try {
        const response = await generateContentWithRetry({
            model: GEMINI_MODEL,
            contents: prompt,
            config: {
                thinkingConfig: { thinkingBudget: 2048 },
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        vietnameseTitle: { type: Type.STRING },
                        englishTitle: { type: Type.STRING },
                        vietnameseArticle: { type: Type.STRING },
                        englishArticle: { type: Type.STRING },
                        socialMediaSummaryVI: { type: Type.STRING },
                        socialMediaSummaryEN: { type: Type.STRING },
                        imagePrompt: { type: Type.STRING },
                    },
                },
            },
        });
        return parseJsonResponse<ArticleData>(response.text, "tạo bài báo");
    } catch (error) {
        throw handleGeminiError(error, "tạo bài báo");
    }
}

/**
 * Tạo kịch bản phim song ngữ.
 */
export async function generateScript(formState: ScriptFormState): Promise<{ vietnameseScript: string; englishScript: string }> {
    const characterDescriptions = formState.characters.length > 0
        ? formState.characters.map(char => `
- Tên nhân vật: ${char.name}
  - Vai trò: ${char.role}
  - Mô tả chi tiết (Ngoại hình, tính cách): ${char.description}
  - Giọng nói: ${char.voice}
  - Có ảnh tham chiếu: ${char.referenceImage ? 'Có' : 'Không'}
`).join('')
        : 'Không có nhân vật cụ thể nào được mô tả.';


    const promptText = `
Nhiệm vụ: Viết một kịch bản phim chi tiết (bằng tiếng Việt) dựa trên bản tóm tắt sáng tạo (creative brief) có cấu trúc được cung cấp. Sau đó, dịch kịch bản đó sang tiếng Anh.

QUAN TRỌNG: Các ảnh tham chiếu cho nhân vật có thể đã được cung cấp. Hãy phân tích hình ảnh (nếu có) để đảm bảo mô tả trong kịch bản (hành động, ngoại hình, trang phục) khớp với hình ảnh đó.

--- CREATIVE BRIEF ---

### 1. Ý TƯỞNG & CỐT TRUYỆN (SCRIPT)
- **Ý tưởng chính:** ${formState.theme}
- **Phong cách thoại:** ${formState.script_style}
- **Gợi ý góc máy (Camera Shots):** ${formState.script_cameraShots.join(', ')}

### 2. DÀN NHÂN VẬT (CAST)
${characterDescriptions}

### 3. BỐI CẢNH (SCENE)
- **Loại bối cảnh:** ${formState.scene_type.join(', ')}
- **Mô tả chi tiết bối cảnh:** ${formState.scene_description}
- **Bảng màu chủ đạo (Color Palette):** ${formState.scene_colorPalette}

### 4. ÂM THANH (AUDIO)
- **Giọng đọc AI (Tổng thể/Dẫn chuyện):** ${formState.audio_voice}
- **Nhạc nền:** ${formState.audio_music}
- **Mô tả hiệu ứng âm thanh (SFX):** ${formState.audio_sfx_description}

### 5. THÔNG SỐ XUẤT BẢN (PUBLISH)
- **Định dạng & Tỉ lệ:** ${formState.publish_format}
- **Chất lượng:** ${formState.publish_quality}
- **Bao gồm bản dịch tiếng Anh:** ${formState.includeEnglish ? 'Có' : 'Không'}

--- YÊU CẦU ĐẦU RA (JSON OUTPUT) ---
- **vietnameseScript**: Toàn bộ kịch bản bằng tiếng Việt, được định dạng chuyên nghiệp với tiêu đề cảnh (ví dụ: "SCENE 1. EXT. ALIEN PLANET - DAY"), mô tả hành động và lời thoại của nhân vật. Kịch bản phải phản ánh tất cả các chi tiết trong creative brief.
- **englishScript**: ${formState.includeEnglish ? "Bản dịch tiếng Anh chính xác và tự nhiên của kịch bản tiếng Việt." : '""'}
`;

    const parts: any[] = [];

    formState.characters.forEach(char => {
        if (char.referenceImage) {
            parts.push({
                inlineData: {
                    data: char.referenceImage.base64,
                    mimeType: char.referenceImage.mimeType,
                },
            });
            parts.push({
                text: `(Đây là ảnh tham chiếu cho nhân vật tên: ${char.name})`
            });
        }
    });

    parts.push({ text: promptText });


    try {
        const response = await generateContentWithRetry({
            model: GEMINI_PRO_MODEL,
            contents: { parts },
            config: {
                systemInstruction: "Bạn là một biên kịch phim đẳng cấp quốc tế. Bạn am hiểu sâu sắc về cấu trúc kịch bản, ngôn ngữ điện ảnh, chỉ đạo nghệ thuật và tâm lý nhân vật.",
                thinkingConfig: { thinkingBudget: 8192 },
                responseMimeType: "application/json",
                responseSchema: { type: Type.OBJECT, properties: { vietnameseScript: { type: Type.STRING }, englishScript: { type: Type.STRING } } },
            },
        });
        return parseJsonResponse<{ vietnameseScript: string; englishScript: string }>(response.text, "tạo kịch bản");
    } catch (error)
{
        throw handleGeminiError(error, "tạo kịch bản");
    }
}

/**
 * Phân tích văn bản để tạo prompts cho video.
 */
export async function analyzeTextForPrompts(text: string, sceneCountTarget: string): Promise<ScenePrompt[]> {
    const prompt = `
Nhiệm vụ: Phân tích văn bản kịch bản/truyện thành một chuỗi các phân cảnh trực quan CÓ TÍNH LIÊN KẾT.
Số cảnh mục tiêu: ${sceneCountTarget}.

Văn bản cần phân tích:
---
${text.substring(0, 15000)}
---

QUY TẮC QUAN TRỌNG:
1. Luôn trả về một MẢNG (ARRAY) JSON hợp lệ, ngay cả khi không có cảnh nào được tìm thấy (trả về mảng rỗng []).
2. Mỗi đối tượng trong mảng phải tuân thủ nghiêm ngặt cấu trúc JSON đã cho.
3. 'prompt' phải bằng TIẾNG ANH, tập trung vào mô tả hình ảnh, chi tiết, nghệ thuật.
4. 'description', 'action', 'dialogue' phải bằng TIẾNG VIỆT, tóm tắt nội dung cảnh.
5. Tạo sự liên kết giữa các cảnh, đảm bảo tính nhất quán của nhân vật và bối cảnh.

JSON Output Schema:
- scene: (Number) Số thứ tự cảnh.
- description: (String, Tiếng Việt) Mô tả ngắn gọn bối cảnh và mục đích của cảnh.
- action: (String, Tiếng Việt) Hành động chính xảy ra trong cảnh.
- dialogue: (String, Tiếng Việt) Lời thoại quan trọng nhất (nếu có).
- prompt: (String, Tiếng Anh) Prompt chi tiết, nghệ thuật để tạo video/ảnh cho cảnh này.
`;
    try {
        const response = await generateContentWithRetry({
            model: GEMINI_PRO_MODEL,
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            scene: { type: Type.INTEGER },
                            description: { type: Type.STRING },
                            action: { type: Type.STRING },
                            dialogue: { type: Type.STRING },
                            prompt: { type: Type.STRING },
                        },
                    },
                },
                thinkingConfig: { thinkingBudget: 4096 }
            },
        });
        return parseJsonResponse<ScenePrompt[]>(response.text, "phân tích cảnh");
    } catch (error) {
        throw handleGeminiError(error, "phân tích cảnh");
    }
}

/**
 * Tạo một hình ảnh từ prompt.
 */
export async function generateImage(prompt: string, quality: string, aspectRatio: string): Promise<string> {
    try {
        const response = await generateImagesWithRetry({
            model: IMAGE_GEN_MODEL,
            prompt: `${prompt}, ${quality}, cinematic, high detail`,
            config: {
                numberOfImages: 1,
                outputMimeType: 'image/jpeg',
                aspectRatio: aspectRatio as "1:1" | "16:9" | "9:16" | "4:3",
            },
        });

        const image = response.generatedImages[0]?.image?.imageBytes;
        if (!image) {
            throw new Error("API không trả về dữ liệu hình ảnh.");
        }
        return image;
    } catch (error) {
        throw handleGeminiError(error, "tạo hình ảnh");
    }
}

/**
 * Khởi tạo quá trình tạo video và trả về operation ban đầu.
 */
export async function generateVideo(prompt: string, resolution: string, aspectRatio: '16:9' | '9:16'): Promise<any> {
    try {
        const validResolution = ['720p', '1080p'].includes(resolution) ? resolution : '1080p';
        const freshAi = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const operation = await freshAi.models.generateVideos({
            model: VEO_MODEL,
            prompt,
            config: {
                numberOfVideos: 1,
                resolution: validResolution as '720p' | '1080p',
                aspectRatio: aspectRatio,
            }
        });
        return operation;
    } catch (error) {
        throw handleGeminiError(error, "khởi tạo video generation");
    }
}

/**
 * Lấy trạng thái cập nhật của một video generation operation.
 */
export async function getVideosOperation(operation: any): Promise<any> {
    try {
        const freshAi = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const updatedOperation = await freshAi.operations.getVideosOperation({ operation });
        return updatedOperation;
    } catch (error) {
        throw handleGeminiError(error, "kiểm tra trạng thái video");
    }
}


// =================================================================
// AD IMAGE GENERATION SERVICES
// =================================================================

/**
 * Tạo các biến thể ảnh quảng cáo.
 */
export async function generateAdImage(formState: AdImageFormState): Promise<string[]> {
    const { files, prompt, variations } = formState;

    const parts: any[] = files.map(file => ({
        inlineData: { data: file.base64, mimeType: file.mimeType }
    }));

    const fileDescriptions = files.map((file, index) => 
        `Image ${index + 1} has the role: ${file.role}.`
    ).join(' ');

    const fullPrompt = `
Task: Generate an advertisement image.
Reference Images: Analyze the ${files.length} images provided. ${fileDescriptions}
Creative Brief: ${prompt}
---
Based on the roles and creative brief, create a compelling advertisement image.
`;
    parts.push({ text: fullPrompt });

    try {
         const response = await generateImagesWithRetry({
            model: IMAGE_GEN_MODEL,
            prompt: fullPrompt,
            config: {
                numberOfImages: variations,
                outputMimeType: 'image/jpeg',
                aspectRatio: '1:1',
            },
        });

        if (!response.generatedImages || response.generatedImages.length === 0) {
            throw new Error("API không trả về bất kỳ hình ảnh nào.");
        }

        return response.generatedImages.map(img => img.image.imageBytes);

    } catch (error) {
        throw handleGeminiError(error, "tạo ảnh quảng cáo");
    }
}

/**
 * Chỉnh sửa ảnh quảng cáo.
 */
export async function editAdImage(baseImage: AdImageFile, referenceFiles: AdImageFile[], prompt: string): Promise<string> {
    const parts: any[] = [];

    // Add the main image to be edited first
    parts.push({ inlineData: { data: baseImage.base64, mimeType: baseImage.mimeType } });
    parts.push({ text: "(This is the base image to be edited)" });

    // Add other reference images
    referenceFiles.forEach(file => {
        parts.push({ inlineData: { data: file.base64, mimeType: file.mimeType } });
        parts.push({ text: `(This is a reference image with role: ${file.role})` });
    });

    // Add the final text prompt
    parts.push({ text: prompt });

    try {
        const response = await generateContentWithRetry({
            model: IMAGE_EDIT_MODEL,
            contents: { parts },
            config: {
                responseModalities: [Modality.IMAGE],
            },
        });

        for (const part of response.candidates[0].content.parts) {
            if (part.inlineData && part.inlineData.data) {
                return part.inlineData.data;
            }
        }

        const fallbackText = response.text?.trim();
        if (fallbackText) {
            throw new Error(`AI không tạo ra ảnh. Phản hồi: ${fallbackText}`);
        }

        throw new Error("Không nhận được hình ảnh đã chỉnh sửa từ AI.");
    } catch (error) {
        throw handleGeminiError(error, "chỉnh sửa ảnh quảng cáo");
    }
}


/**
 * Tạo gợi ý quảng cáo dựa trên thông tin sản phẩm.
 */
export async function generateAdIdeas(productInfo: string): Promise<AdSuggestion[]> {
    const prompt = `
Nhiệm vụ: Dựa trên thông tin sản phẩm được cung cấp, hãy tạo ra 3 ý tưởng quảng cáo độc đáo.
Thông tin sản phẩm: "${productInfo}"

QUY TẮC QUAN TRỌNG:
1. Mỗi ý tưởng phải bao gồm một tiêu đề (title), mô tả (description), và một prompt chi tiết bằng tiếng Anh để tạo ảnh quảng cáo.
2. 'prompt' phải tập trung vào hình ảnh, nghệ thuật, ánh sáng, và bố cục.

JSON Output (Mảng chứa 3 đối tượng):
- title: (String, Tiếng Việt) Tiêu đề hấp dẫn cho ý tưởng.
- description: (String, Tiếng Việt) Mô tả ngắn gọn về concept quảng cáo.
- prompt: (String, Tiếng Anh) Prompt chi tiết để tạo ảnh.
`;
    try {
        const response = await generateContentWithRetry({
            model: GEMINI_MODEL,
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            title: { type: Type.STRING },
                            description: { type: Type.STRING },
                            prompt: { type: Type.STRING },
                        },
                    },
                },
            },
        });
        const suggestions = parseJsonResponse<AdSuggestion[]>(response.text, "tạo gợi ý quảng cáo");
        if (!Array.isArray(suggestions) || suggestions.length === 0) {
            throw new Error("Phản hồi từ AI không chứa gợi ý hợp lệ.");
        }
        return suggestions;
    } catch (error) {
        throw handleGeminiError(error, "tạo gợi ý quảng cáo");
    }
}

