            const storyData = await generateStory(storyFormState, accumulatedStoryText);

            if (!storyData || !storyData.story || !storyData.story.storyText) {
                throw new Error(`Không thể tạo nội dung cho chương ${currentChapter}.`);
            }

            const { storyText, voiceProfile: generatedVoiceProfile, synopsis: generatedSynopsis } = storyData.story;

            const newChapterText = accumulatedStoryText ? `\n\n\n${storyText}` : storyText;
            accumulatedStoryText += newChapterText;

            if (currentChapter === 1) {
                setSynopsis(generatedSynopsis);
                setVoiceProfile(generatedVoiceProfile);
            }
            setFullStoryText(accumulatedStoryText);
            setPages(paginateStory(accumulatedStoryText));
