import type { StoryFormState, StoryGenerationResponse, ScriptFormState, ScenePrompt, ArticleData, AdImageFormState, AdSuggestion, AdImageFile, AdImageRole } from '../types';

const GEMINI_MODEL = "gemini-2.5-flash";
const GEMINI_PRO_MODEL = "gemini-3-pro-preview";
const IMAGE_GEN_MODEL = "imagen-4.0-generate-001";
const IMAGE_EDIT_MODEL = "gemini-2.5-flash-image"; // Multimodal model for image input -> image output
const VEO_MODEL = "veo-3.1-fast-generate-preview";

// Khởi tạo client một lần duy nhất ở cấp độ module để tái sử dụng.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });


/**
 * Một hàm trợ giúp bao bọc lệnh gọi API Gemini với cơ chế thử lại.
 * Nó sử dụng thuật toán exponential backoff với jitter để xử lý lỗi giới hạn tốc độ (429).
 * @param params Các tham số cho lệnh gọi generateContent.
 * @param maxRetries Số lần thử lại tối đa.
 * @param initialDelay Độ trễ ban đầu tính bằng mili giây trước lần thử lại đầu tiên.
 * @returns Một promise phân giải thành phản hồi của API.
 */
async function generateContentWithRetry(
    params: { model: string; contents: any; config?: any; },
    maxRetries = 3,
    initialDelay = 2000 // Bắt đầu với độ trễ 2 giây
): Promise<GenerateContentResponse> {
    let attempt = 0;
    while (attempt < maxRetries) {
        try {
            const response = await ai.models.generateContent(params);
            return response;
        } catch (error) {
            attempt++;
            const isRetryable = error instanceof Error && (
                error.message.includes('429') ||
                error.message.toLowerCase().includes('rate limit') ||
                error.message.includes('500') ||
                error.message.toLowerCase().includes('xhr error')
            );
            if (isRetryable && attempt < maxRetries) {
                const delay = initialDelay * (2 ** (attempt - 1)) + Math.random() * 1000;
                console.warn(`Lệnh gọi API thất bại, thử lại sau ${Math.round(delay / 1000)}s... (Lần thử ${attempt}/${maxRetries})`);
                await new Promise(resolve => setTimeout(resolve, delay));
            } else {
                console.error(`Lệnh gọi API thất bại sau ${attempt} lần thử.`, error);
                throw error;
            }
        }
    }
    throw new Error("Lệnh gọi API thất bại sau khi đạt đến số lần thử lại tối đa.");
}

/**
 * Một hàm trợ giúp bao bọc lệnh gọi API generateImages với cơ chế thử lại.
 * @param params Các tham số cho lệnh gọi generateImages.
 * @param maxRetries Số lần thử lại tối đa.
 * @param initialDelay Độ trễ ban đầu tính bằng mili giây.
 * @returns Một promise phân giải thành phản hồi của API.
 */
async function generateImagesWithRetry(
    params: { model: string; prompt: string; config?: any; },
    maxRetries = 3,
    initialDelay = 2000
): Promise<{ generatedImages: { image: { imageBytes: string } }[] }> {
    let attempt = 0;
    while (attempt < maxRetries) {
        try {
            const response = await ai.models.generateImages(params);
            return response;
        } catch (error) {
            attempt++;
            const isRetryable = error instanceof Error && (
                error.message.includes('429') ||
                error.message.toLowerCase().includes('rate limit') ||
                error.message.includes('500') ||
                error.message.toLowerCase().includes('xhr error')
            );

            if (isRetryable && attempt < maxRetries) {
                const delay = initialDelay * (2 ** (attempt - 1)) + Math.random() * 1000;
                console.warn(`Lệnh gọi API generateImages thất bại, thử lại sau ${Math.round(delay / 1000)}s... (Lần thử ${attempt}/${maxRetries})`);
                await new Promise(resolve => setTimeout(resolve, delay));
            } else {
                console.error(`Lệnh gọi API generateImages thất bại sau ${attempt} lần thử.`, error);
                throw error;
            }
        }
    }
    throw new Error("Lệnh gọi API generateImages thất bại sau khi đạt đến số lần thử lại tối đa.");
}


/**
 * Trình xử lý lỗi tập trung cho các lệnh gọi API Gemini.
 * @param error Đối tượng lỗi đã bắt được.
 * @param context Một chuỗi mô tả ngữ cảnh của lệnh gọi API (ví dụ: "tạo câu chuyện").
 * @returns Một đối tượng Error mới với thông báo thân thiện với người dùng.
 */
function handleGeminiError(error: unknown, context: string): Error {
    console.error(`Lỗi trong lúc gọi API Gemini (${context}):`, error);
    let errorMessage = `Lỗi khi ${context}. Vui lòng thử lại.`;

    if (error instanceof Error) {
        const errorMsgLower = error.message.toLowerCase();
        if (errorMsgLower.includes('quota') || errorMsgLower.includes('resource_exhausted') || errorMsgLower.includes('429')) {
             errorMessage = "Lỗi: Hạn ngạch API đã hết. Vui lòng kiểm tra gói dịch vụ của bạn hoặc thử lại sau khi hạn ngạch được làm mới.";
        } else if (errorMsgLower.includes('api key not valid') || errorMsgLower.includes('requested entity was not found')) {
            errorMessage = "Lỗi: API Key không hợp lệ hoặc không được tìm thấy. Vui lòng chọn lại API Key hợp lệ và thử lại.";
        } else if (errorMsgLower.includes('json')) {
            errorMessage = `Lỗi khi phân tích phản hồi ${context}. Phản hồi không phải là JSON hợp lệ.`;
        } else if (errorMsgLower.includes('safety')) {
            errorMessage = "Nội dung yêu cầu đã bị chặn vì lý do an toàn. Vui lòng thử lại với một chủ đề khác.";
        } else {
             errorMessage = `Lỗi từ Gemini: ${error.message}`;
        }
    }
    return new Error(errorMessage);
}

const parseJsonResponse = <T>(responseText: string, context: string): T => {
    try {
        const parsedData = JSON.parse(responseText.trim());
        return parsedData as T;
    } catch (e) {
        throw new Error(`Phản hồi từ AI (${context}) không có cấu trúc JSON hợp lệ.`);
    }
};

