      setError("Không thể tải các câu chuyện đã lưu.");
    }
  }, []);

  const resetOutput = () => {
    setError(null);
    setPages([]);
    setVoiceProfile(null);
    setCurrentFormState(null);
    setFullStoryText(null);
    setSynopsis(null);
    setIsBilingual(false);
