    setThumbnailEditStates({});
    setEditStatuses({});
  }

  const handleGenerateStory = useCallback(async () => {
    setIsLoading(true);
    resetOutput();

    let accumulatedStoryText = '';
    const totalChapters = storyFormState.chapters;
    let currentChapter = 1;

    try {
        for (currentChapter = 1; currentChapter <= totalChapters; currentChapter++) {
            setStatusMessage(`Đang suy nghĩ và sáng tác chương ${currentChapter}/${totalChapters}...`);

            const storyData = await generateStory(storyFormState, accumulatedStoryText);

            if (!storyData || !storyData.story || !storyData.story.storyText) {
                throw new Error(`Không thể tạo nội dung cho chương ${currentChapter}.`);
            }

            const { storyText, voiceProfile: generatedVoiceProfile, synopsis: generatedSynopsis } = storyData.story;

            const newChapterText = accumulatedStoryText ? `\n\n\n${storyText}` : storyText;
            accumulatedStoryText += newChapterText;

            if (currentChapter === 1) {
                setSynopsis(generatedSynopsis);
                setVoiceProfile(generatedVoiceProfile);
            }
            setFullStoryText(accumulatedStoryText);
            setPages(paginateStory(accumulatedStoryText));
        }

        setCurrentFormState(storyFormState);

    } catch (err) {
      console.error(err);
      const errorMessage = err instanceof Error ? err.message : `Đã xảy ra lỗi không xác định. Vui lòng thử lại.`;
      setError(`Lỗi ở chương ${currentChapter}: ${errorMessage}`);
    } finally {
      setIsLoading(false);
      setStatusMessage('');
    }
  }, [storyFormState]);

  const handleGenerateArticle = useCallback(async (urls: string[]) => {
    setIsLoading(true);
    resetOutput();

    try {
      setStatusMessage('Đang phân tích, tổng hợp và viết bài báo song ngữ...');
      const result = await generateArticleFromUrls(urls);
      if (!result || !result.vietnameseArticle) {
        throw new Error('Không thể tạo nội dung bài báo.');
      }

      setArticleData(result);

      const generatedPages = paginateStory(result.vietnameseArticle); 
       if(generatedPages.length === 0) {
        throw new Error('Nội dung bài báo được tạo ra trống.');
      }

      setPages(generatedPages);
      setFullStoryText(result.vietnameseArticle);

    } catch (err) {
