 const handleGenerateVideo = useCallback(async (prompt: string, scene: number, quality: string, aspectRatio: '1:1' | '16:9' | '9:16' | '4:3') => {
    setVideoStatuses(prev => ({ ...prev, [scene]: { status: 'generating' } }));

    try {
        if (window.aistudio) {
            const hasKey = await window.aistudio.hasSelectedApiKey();
            if (!hasKey) {
                await window.aistudio.openSelectKey();
                // Assume key selection is successful to proceed.
            }
        }

        const validAspectRatio = aspectRatio === '9:16' ? '9:16' : '16:9';
        const initialOperation = await generateVideo(prompt, quality, validAspectRatio);
        setVideoStatuses(prev => ({ ...prev, [scene]: { status: 'polling', operation: initialOperation } }));

        const pollOperation = async (operation: any) => {
            const updatedOperation = await getVideosOperation(operation);

            if (updatedOperation.done) {
                if (updatedOperation.error) {
                    throw new Error(updatedOperation.error.message);
                }
                const downloadLink = updatedOperation.response?.generatedVideos?.[0]?.video?.uri;
                if (!downloadLink) throw new Error("Không tìm thấy link tải video trong phản hồi.");

                const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
                if (!response.ok) throw new Error(`Lỗi khi tải video: ${response.statusText}`);

                const blob = await response.blob();
                const videoUrl = URL.createObjectURL(blob);
                setVideoStatuses(prev => ({ ...prev, [scene]: { status: 'completed', videoUrl } }));
            } else {
                setVideoStatuses(prev => ({ ...prev, [scene]: { status: 'polling', operation: updatedOperation } }));
                setTimeout(() => pollOperation(updatedOperation), 10000); // Poll every 10s
            }
        };

        pollOperation(initialOperation);

    } catch (err) {
        console.error(err);
        const errorMsg = err instanceof Error ? err.message : 'Lỗi không xác định khi tạo video.';
        setVideoStatuses(prev => ({ ...prev, [scene]: { status: 'failed', error: errorMsg } }));
    }
 }, []);


