            }
        }
    }
    throw new Error("Image generation failed after maximum retries.");
}

function handleGeminiError(error: unknown, context: string): Error {
    console.error(`Gemini API Error (${context}):`, error);
    let errorMessage = `Lỗi khi ${context}. Vui lòng thử lại.`;
    if (error instanceof Error) {
        const msg = error.message.toLowerCase();
        if (msg.includes('quota') || msg.includes('429')) errorMessage = "Hạn ngạch API đã hết. Vui lòng thử lại sau.";
        else if (msg.includes('safety')) errorMessage = "Nội dung bị chặn do vi phạm chính sách an toàn.";
        else errorMessage = error.message;
    }
    return new Error(errorMessage);
}

const parseJsonResponse = <T>(responseText: string, context: string): T => {
    try {
        const cleanJson = responseText.trim().replace(/^```json/, '').replace(/```$/, '');
        return JSON.parse(cleanJson) as T;
    } catch (e) {
        throw new Error(`Phản hồi từ AI (${context}) không đúng định dạng dữ liệu.`);
    }
};

