export async function generateAdImage(formState: AdImageFormState): Promise<string[]> {
    const { files, prompt, variations } = formState;
    const parts: any[] = files.map(file => ({ inlineData: { data: file.base64, mimeType: file.mimeType }, text: `Role: ${file.role}` }));
    parts.push({ text: `Create a professional advertisement image: ${prompt}` });

