         const res = await generateContentWithRetry({
            model: IMAGE_EDIT_MODEL,
            contents: { parts },
            config: {
                systemInstruction: "Bạn là một chuyên gia thiết kế đồ họa quảng cáo.",
                responseModalities: [Modality.IMAGE],
            },
