        if (!imagePart?.inlineData?.data) throw new Error("AI không tạo được ảnh.");
        return imagePart.inlineData.data;
    };

    try {
        return await Promise.all(Array.from({ length: variations }).map(() => generateSingle()));
    } catch (error) {
        throw handleGeminiError(error, "tạo ảnh quảng cáo");
    }
}

