import React, { useState, useEffect, useCallback } from 'react';
import type { StoryPage, VoiceProfile, ScenePrompt, ImageGenerationStatus, ArticleData, VideoGenerationStatus } from '../types';

interface StoryViewerProps {
  pages: StoryPage[];
  fullStoryText: string | null;
  voiceProfile: VoiceProfile | null;
  synopsis: string | null;
  title: string;
  onAnalyzeScenes: () => void;
  isAnalyzingScenes: boolean;
  scenePrompts: ScenePrompt[] | null;
  analysisError: string | null;
  onGenerateImage: (prompt: string, scene: number, quality: string, aspectRatio: '1:1' | '16:9' | '9:16' | '4:3') => void;
  imageStatuses: Record<number, ImageGenerationStatus>;
  onGenerateVideo: (prompt: string, scene: number, quality: string, aspectRatio: '1:1' | '16:9' | '9:16' | '4:3') => void;
  videoStatuses: Record<number, VideoGenerationStatus>;
  sceneCountTarget: string;
  onSceneCountChange: (value: string) => void;
  articleData: ArticleData | null;
  onDownloadMedia: (url: string, filename: string) => void;
}

const StoryViewer: React.FC<StoryViewerProps> = ({ 
    pages, 
    voiceProfile, 
    synopsis, 
    title,
    scenePrompts,
    onDownloadMedia
}) => {
    const [currentPageIndex, setCurrentPageIndex] = useState(0);
    const [isPlaying, setIsPlaying] = useState(false);
    const [voices, setVoices] = useState<SpeechSynthesisVoice[]>([]);

    const currentPage = pages[currentPageIndex];

    useEffect(() => {
        const loadVoices = () => setVoices(window.speechSynthesis.getVoices());
        if ('speechSynthesis' in window) {
            window.speechSynthesis.onvoiceschanged = loadVoices;
            loadVoices();
        }
        return () => {
            if ('speechSynthesis' in window) {
                window.speechSynthesis.onvoiceschanged = null;
                if (window.speechSynthesis.speaking) window.speechSynthesis.cancel();
            }
        };
    }, []);

    const speakText = useCallback((text: string, onEndCallback: () => void) => {
        if (window.speechSynthesis.speaking) window.speechSynthesis.cancel();
        const utterance = new SpeechSynthesisUtterance(text);
        const vnVoice = voices.find(v => v.lang.startsWith('vi-VN'));
        if (vnVoice) utterance.voice = vnVoice;
        utterance.lang = 'vi-VN';
        if (voiceProfile) {
            utterance.rate = voiceProfile.speed === 'slow' ? 0.8 : voiceProfile.speed === 'fast' ? 1.2 : 1.0;
        }
        utterance.onend = onEndCallback;
        window.speechSynthesis.speak(utterance);
    }, [voices, voiceProfile]);

    const changePage = (direction: 'next' | 'prev') => {
        if ('speechSynthesis' in window) window.speechSynthesis.cancel();
        setIsPlaying(false);
        if (direction === 'next' && currentPageIndex < pages.length - 1) setCurrentPageIndex(prev => prev + 1);
        else if (direction === 'prev' && currentPageIndex > 0) setCurrentPageIndex(prev => prev - 1);
    };

    const handleToggleVoice = () => {
        if (isPlaying) {
            window.speechSynthesis.cancel();
            setIsPlaying(false);
        } else {
            setIsPlaying(true);
            speakText(currentPage.text, () => setIsPlaying(false));
        }
    };

    return (
        <div className="space-y-6 animate-fade-in">
            <div className="bg-white p-8 rounded-[2.5rem] border border-slate-200 shadow-sm relative overflow-hidden">
                <div className="absolute top-0 left-0 w-2 h-full bg-indigo-600"></div>
                <h3 className="text-2xl font-bold text-slate-800 mb-2">{title}</h3>
                {synopsis && <p className="text-sm text-slate-500 italic mb-6">"{synopsis}"</p>}

                <div className="bg-slate-50 p-8 rounded-3xl min-h-[300px] flex items-center border border-slate-100 mb-8">
                    <p className="font-serif text-xl leading-relaxed text-slate-800 text-left w-full">
                        {currentPage?.text}
                    </p>
                </div>

                <div className="flex items-center justify-between">
                    <div className="flex items-center gap-4">
                        <button onClick={() => changePage('prev')} disabled={currentPageIndex === 0}
                            className="p-3 rounded-2xl bg-white border border-slate-200 text-slate-600 hover:bg-slate-50 disabled:opacity-30 shadow-sm">
                            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 19l-7-7 7-7"/></svg>
                        </button>
                        <span className="text-xs font-bold text-slate-400 uppercase tracking-widest">{currentPageIndex + 1} / {pages.length}</span>
                        <button onClick={() => changePage('next')} disabled={currentPageIndex === pages.length - 1}
                            className="p-3 rounded-2xl bg-white border border-slate-200 text-slate-600 hover:bg-slate-50 disabled:opacity-30 shadow-sm">
                            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5l7 7-7 7"/></svg>
                        </button>
                    </div>

                    <button onClick={handleToggleVoice} 
                        className={`flex items-center gap-2 px-6 py-3 rounded-2xl font-bold text-sm transition-all shadow-lg ${isPlaying ? 'bg-indigo-600 text-white shadow-indigo-200' : 'bg-white border border-slate-200 text-slate-700'}`}>
                        {isPlaying ? (
                            <>
                                <svg className="w-5 h-5 animate-pulse" fill="currentColor" viewBox="0 0 20 20"><path d="M10 18a8 8 0 100-16 8 8 0 000 16zM8 7a1 1 0 00-1 1v4a1 1 0 001 1h4a1 1 0 001-1V8a1 1 0 00-1-1H8z"/></svg>
                                Đang đọc...
                            </>
                        ) : (
                            <>
                                <svg className="w-5 h-5 text-indigo-500" fill="currentColor" viewBox="0 0 20 20"><path d="M9.383 3.076A1 1 0 0110 4v12a1 1 0 01-1.707.707L4.586 13H2a1 1 0 01-1-1V8a1 1 0 011-1h2.586l3.707-3.707a1 1 0 011.09-.217zM14.657 2.929a1 1 0 011.414 0A9.972 9.972 0 0119 10a9.972 9.972 0 01-2.929 7.071 1 1 0 01-1.414-1.414A7.971 7.971 0 0017 10c0-2.21-.894-4.208-2.343-5.657a1 1 0 010-1.414zm-2.829 2.828a1 1 0 011.415 0A5.983 5.983 0 0115 10a5.983 5.983 0 01-1.757 4.243 1 1 0 01-1.415-1.415A3.984 3.984 0 0013 10a3.984 3.984 0 00-1.172-2.828a1 1 0 010-1.415z"/></svg>
                                Nghe AI đọc
                            </>
                        )}
                    </button>
                </div>
            </div>

            {scenePrompts && (
                <div className="bg-white p-8 rounded-3xl border border-indigo-50 shadow-sm space-y-4">
                    <h4 className="text-base font-bold text-slate-800 flex items-center gap-2">
                        <span className="w-2 h-2 bg-indigo-600 rounded-full"></span>
                        Phân cảnh tối ưu (Storyboard)
                    </h4>
                    <div className="grid grid-cols-1 gap-4">
                        {scenePrompts.map((p, idx) => (
                            <div key={idx} className="bg-slate-50 p-5 rounded-2xl border border-slate-100 flex gap-4 items-start">
                                <div className="w-8 h-8 rounded-full bg-white border border-slate-200 flex items-center justify-center text-[10px] font-bold text-indigo-600 shrink-0 shadow-sm">{p.scene}</div>
                                <div className="space-y-2">
                                    <p className="text-xs font-bold text-slate-700 uppercase tracking-wide">Hành động: {p.action}</p>
                                    <p className="text-xs text-slate-500 italic">Prompt: {p.prompt}</p>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            )}
        </div>
    );
};

