import { GoogleGenAI, Type, GenerateContentResponse, Modality } from "@google/genai";
import type { StoryFormState, StoryGenerationResponse, ScriptFormState, ScenePrompt, ArticleData, AdImageFormState, AdSuggestion, AdImageFile, AdImageRole, AffiliateFormState, AffiliateScriptResult } from '../types';

const GEMINI_MODEL = "gemini-3-flash-preview"; 
const GEMINI_PRO_MODEL = "gemini-3-pro-preview";
const IMAGE_GEN_MODEL = "imagen-4.0-generate-001";
const IMAGE_EDIT_MODEL = "gemini-2.5-flash-image"; 
const VEO_MODEL = "veo-3.1-fast-generate-preview";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

async function generateContentWithRetry(
    params: { model: string; contents: any; config?: any; },
    maxRetries = 3,
    initialDelay = 2000
): Promise<GenerateContentResponse> {
    let attempt = 0;
    while (attempt < maxRetries) {
        try {
            const response = await ai.models.generateContent(params);
            return response;
        } catch (error) {
            attempt++;
            if (attempt >= maxRetries) throw error;
            const delay = initialDelay * (2 ** (attempt - 1)) + Math.random() * 1000;
            await new Promise(resolve => setTimeout(resolve, delay));
        }
    }
    throw new Error("Failed after retries");
}

async function generateImagesWithRetry(
    params: { model: string; prompt: string; config?: any; },
    maxRetries = 3
): Promise<{ generatedImages: { image: { imageBytes: string } }[] }> {
    let attempt = 0;
    while (attempt < maxRetries) {
        try {
            return await ai.models.generateImages(params);
        } catch (error) {
            attempt++;
            if (attempt >= maxRetries) throw error;
            await new Promise(resolve => setTimeout(resolve, 2000));
        }
    }
    throw new Error("Image gen failed");
}

function handleGeminiError(error: unknown, context: string): Error {
    console.error(`Gemini Error (${context}):`, error);
    return new Error(error instanceof Error ? error.message : `Lỗi ${context}`);
}

const parseJsonResponse = <T>(responseText: string, context: string): T => {
    try {
        const cleanJson = responseText.trim().replace(/^```json/, '').replace(/```$/, '');
        return JSON.parse(cleanJson) as T;
    } catch (e) {
        throw new Error(`AI response for ${context} is not valid JSON`);
    }
};

export async function generateAffiliateScript(formState: AffiliateFormState): Promise<AffiliateScriptResult> {
    const prompt = `
Hãy đóng vai một chuyên gia Viral Marketing cho ${formState.platform}.
Sản phẩm: ${formState.productName}
Đặc điểm: ${formState.productFeatures}
Đối tượng: ${formState.targetAudience}
Loại kịch bản: ${formState.scriptType}
Tông giọng: ${formState.tone}

Yêu cầu:
1. Viết kịch bản video ngắn (30-60s) áp dụng công thức chuyển đổi cao.
2. Tạo 01 "Master Flow Prompt" (Tiếng Anh): Đây là prompt mô tả nhân vật và bối cảnh CHỦ ĐẠO để dùng làm gốc cho tất cả các ảnh, đảm bảo tính liên mạch.
3. Chia nhỏ kịch bản thành từng Phân cảnh (Scenes) cực kỳ chi tiết để tạo ảnh.

Đầu ra JSON:
- scriptText: Toàn bộ kịch bản văn bản (VI).
- masterFlowPrompt: Prompt tiếng Anh mô tả bối cảnh/nhân vật cố định.
- scenes: Mảng các phân cảnh, mỗi cảnh có prompt tiếng Anh kết hợp với Master Flow Prompt.
`;

    try {
        const response = await generateContentWithRetry({
            model: GEMINI_PRO_MODEL,
            contents: prompt,
            config: {
                systemInstruction: "Bạn là chuyên gia sáng tạo kịch bản Affiliate có tỷ lệ chuyển đổi cao. Bạn am hiểu cách tạo sự liên kết hình ảnh cho AI video flow.",
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        scriptText: { type: Type.STRING },
                        masterFlowPrompt: { type: Type.STRING },
                        scenes: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    scene: { type: Type.INTEGER },
                                    description: { type: Type.STRING },
                                    action: { type: Type.STRING },
                                    dialogue: { type: Type.STRING },
                                    prompt: { type: Type.STRING }
                                }
                            }
                        }
                    }
                }
            }
        });
        return parseJsonResponse<AffiliateScriptResult>(response.text, "tạo kịch bản affiliate");
    } catch (error) {
        throw handleGeminiError(error, "tạo kịch bản affiliate");
    }
}

