import React, { useState } from 'react';
import type { AdImageFormState, AdImageFile, AdImageRole, AdSuggestion } from '../types';

interface AdImageFormProps {
  formState: AdImageFormState;
  onFormChange: (newState: AdImageFormState) => void;
  onSubmit: () => void;
  isLoading: boolean;
  onGenerateSuggestions: (productInfo: string) => void;
  suggestions: AdSuggestion[] | null;
  isSuggesting: boolean;
  suggestionError: string | null;
}

const AdImageForm: React.FC<AdImageFormProps> = ({
  formState,
  onFormChange,
  onSubmit,
  isLoading,
  onGenerateSuggestions,
  suggestions,
  isSuggesting,
  suggestionError,
}) => {
  const [suggestionQuery, setSuggestionQuery] = useState('');

  const handlePromptChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    onFormChange({ ...formState, prompt: e.target.value });
  };

  const handleVariationsChange = (variations: 1 | 3 | 5) => {
    onFormChange({ ...formState, variations });
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files) return;

    Array.from(e.target.files).forEach((file: File) => {
      const reader = new FileReader();
      reader.onload = (event) => {
        if (event.target && typeof event.target.result === 'string') {
          const base64 = event.target.result.split(',')[1];
          const newFile: AdImageFile = {
            id: crypto.randomUUID(),
            name: file.name,
            base64,
            mimeType: file.type,
            role: formState.files.length === 0 ? 'product' : 'none', // Default first image as product
          };
          onFormChange({ ...formState, files: [...formState.files, newFile] });
        }
      };
      reader.readAsDataURL(file);
    });
    e.target.value = '';
  };

  const handleRemoveFile = (id: string) => {
    onFormChange({ ...formState, files: formState.files.filter(f => f.id !== id) });
  };

  const handleRoleChange = (id: string, role: AdImageRole) => {
    onFormChange({ 
        ...formState, 
        files: formState.files.map(f => f.id === id ? { ...f, role } : f) 
    });
  };

  const handleGetSuggestions = () => {
    if (!isSuggesting && suggestionQuery.trim()) {
        onGenerateSuggestions(suggestionQuery.trim());
    }
  };

  const handleUseSuggestion = (prompt: string) => {
      onFormChange({ ...formState, prompt });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (formState.files.length === 0) {
        alert("Vui lòng tải lên ít nhất một ảnh sản phẩm để thực hiện ghép ảnh.");
        return;
    }
    if (!isLoading) {
      onSubmit();
    }
  };

  const roleOptions: { value: AdImageRole; label: string }[] = [
      { value: 'product', label: '📦 Sản phẩm (Chính)' },
      { value: 'model', label: '👤 Người mẫu' },
      { value: 'logo', label: '®️ Thương hiệu' },
      { value: 'background', label: '🏞️ Phông nền tham khảo' },
      { value: 'none', label: '🎨 Tham chiếu khác' },
  ];

  const hasProduct = formState.files.some(f => f.role === 'product');

  return (
    <div className="space-y-10 animate-fade-in">
      {/* Step 1: Upload Assets */}
      <div className="space-y-4">
          <div className="flex items-center justify-between">
              <label className="text-[11px] font-extrabold text-slate-400 uppercase tracking-widest ml-1">
                Bước 1: Tải lên Sản phẩm/Mẫu
              </label>
              {!hasProduct && formState.files.length > 0 && (
                  <span className="text-[10px] font-bold text-rose-500 animate-pulse">Cần định nghĩa 1 ảnh là "Sản phẩm"</span>
              )}
          </div>
          <div className="bg-slate-50 border-2 border-dashed border-slate-200 rounded-[2.5rem] p-8 text-center cursor-pointer hover:border-indigo-400 transition-colors group">
              <input type="file" id="file-upload" multiple accept="image/*" onChange={handleFileChange} className="sr-only" />
              <label htmlFor="file-upload" className="cursor-pointer">
                  <div className="w-12 h-12 bg-white rounded-2xl flex items-center justify-center mx-auto mb-3 shadow-sm group-hover:scale-110 transition-transform">
                      <svg className="w-6 h-6 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12"/></svg>
                  </div>
                  <p className="text-xs font-bold text-slate-500 tracking-tight">Kéo thả ảnh thực tế hoặc <span className="text-indigo-600">chọn tệp</span></p>
                  <p className="text-[10px] text-slate-400 font-medium mt-1 leading-relaxed">AI sẽ dựa trên các ảnh này để ghép vào bối cảnh mới.</p>
              </label>
          </div>

          {formState.files.length > 0 && (
              <div className="grid grid-cols-1 gap-2">
                  {formState.files.map(file => (
                      <div key={file.id} className={`flex items-center gap-3 bg-white p-2 rounded-2xl border transition-all animate-fade-in ${file.role === 'product' ? 'border-indigo-200 shadow-sm ring-2 ring-indigo-50' : 'border-slate-100 shadow-sm'}`}>
                          <img src={`data:${file.mimeType};base64,${file.base64}`} className="w-12 h-12 object-cover rounded-xl" />
                          <div className="flex-grow">
                              <select value={file.role} onChange={(e) => handleRoleChange(file.id, e.target.value as AdImageRole)}
                                  className={`w-full bg-slate-50 border-none text-[10px] font-bold uppercase rounded-lg p-1.5 focus:ring-0 cursor-pointer transition-colors ${file.role === 'product' ? 'text-indigo-600' : 'text-slate-500'}`}>
                                  {roleOptions.map(opt => <option key={opt.value} value={opt.value}>{opt.label}</option>)}
                              </select>
                          </div>
                          <button type="button" onClick={() => handleRemoveFile(file.id)} className="p-2 text-rose-300 hover:text-rose-500 transition-colors">
                              <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M9 2a1 1 0 00-.894.553L7.382 4H4a1 1 0 000 2v10a2 2 0 002 2h8a2 2 0 002-2V6a1 1 0 100-2h-3.382l-.724-1.447A1 1 0 0011 2H9zM7 8a1 1 0 012 0v6a1 1 0 11-2 0V8zm4 0a1 1 0 012 0v6a1 1 0 11-2 0V8z" clipRule="evenodd"/></svg>
                          </button>
                      </div>
                  ))}
              </div>
          )}
      </div>

      {/* Step 2: Smart Idea Section */}
      <div className="bg-indigo-50/30 p-8 rounded-[2.5rem] border border-indigo-100/50 shadow-inner space-y-5">
        <div>
            <label className="text-[11px] font-extrabold text-indigo-600 uppercase tracking-widest ml-1 mb-1 block">
              Bước 2: Ý tưởng & Gợi ý Prompt
            </label>
            <p className="text-[10px] text-slate-400 font-medium">Nhập ý tưởng bối cảnh bạn muốn ghép sản phẩm vào.</p>
        </div>

        <div className="flex flex-col gap-4">
            <div className="relative">
                <input 
                    type="text" 
                    value={suggestionQuery}
                    onChange={(e) => setSuggestionQuery(e.target.value)}
                    onKeyPress={(e) => e.key === 'Enter' && handleGetSuggestions()}
                    className="w-full bg-white border border-slate-200 rounded-2xl p-4 pr-14 text-sm font-bold text-slate-700 placeholder:text-slate-300 shadow-sm focus:ring-4 focus:ring-indigo-100 transition-all"
                    placeholder="VD: Trên mặt bàn đá marble, ánh sáng nắng ban mai..."
                />
                <button 
                    type="button"
                    onClick={handleGetSuggestions}
