                        sceneCountTarget="Tự động"
                        onSceneCountChange={()=>{}}
                        articleData={null}
                        onDownloadMedia={()=>{}}
                    />
                 </div>
             )}

             {!isLoading && pages.length === 0 && adImageStatus.results.length === 0 && <ViewerPlaceholder mode={mode} />}
          </div>
        </main>
      </div>

      <footer className="mt-12 py-12 border-t border-slate-100 bg-white">
        <div className="container mx-auto px-8 flex flex-col items-center gap-6">
