                                                <p className="text-sm text-slate-600 font-medium">"{p.dialogue}"</p>
                                            </div>
                                        )}
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            )}
        </div>
    );
};

