import React, { useState } from 'react';
import type { AdImageFormState, AdImageFile, AdImageRole, AdSuggestion } from '../types';

interface AdImageFormProps {
  formState: AdImageFormState;
  onFormChange: (newState: AdImageFormState) => void;
  onSubmit: () => void;
  isLoading: boolean;
  onGenerateSuggestions: (productInfo: string) => void;
  suggestions: AdSuggestion[] | null;
  isSuggesting: boolean;
  suggestionError: string | null;
}

const AdImageForm: React.FC<AdImageFormProps> = ({
  formState,
  onFormChange,
  onSubmit,
  isLoading,
  onGenerateSuggestions,
  suggestions,
  isSuggesting,
  suggestionError,
}) => {
  const [suggestionQuery, setSuggestionQuery] = useState('');

  const handlePromptChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    onFormChange({ ...formState, prompt: e.target.value });
  };

  const handleVariationsChange = (variations: 1 | 3 | 5) => {
    onFormChange({ ...formState, variations });
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files) return;

    Array.from(e.target.files).forEach((file: File) => {
      const reader = new FileReader();
      reader.onload = (event) => {
        if (event.target && typeof event.target.result === 'string') {
          const base64 = event.target.result.split(',')[1];
          const newFile: AdImageFile = {
            id: crypto.randomUUID(),
            name: file.name,
            base64,
            mimeType: file.type,
            role: formState.files.length === 0 ? 'product' : 'none',
          };
          onFormChange({ ...formState, files: [...formState.files, newFile] });
        }
      };
      reader.readAsDataURL(file);
    });
    e.target.value = '';
  };

  const handleRemoveFile = (id: string) => {
    onFormChange({ ...formState, files: formState.files.filter(f => f.id !== id) });
  };

  const handleRoleChange = (id: string, role: AdImageRole) => {
    onFormChange({ 
        ...formState, 
        files: formState.files.map(f => f.id === id ? { ...f, role } : f) 
    });
  };

  const handleGetSuggestions = () => {
    if (!isSuggesting && suggestionQuery.trim()) {
        onGenerateSuggestions(suggestionQuery.trim());
    }
  };

  const handleUseSuggestion = (prompt: string) => {
      onFormChange({ ...formState, prompt });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (formState.files.length === 0) {
        alert("Vui lòng tải lên ít nhất một ảnh sản phẩm để thực hiện ghép ảnh.");
        return;
    }
    if (!isLoading) {
      onSubmit();
    }
  };

  const roleOptions: { value: AdImageRole; label: string }[] = [
      { value: 'product', label: '📦 Sản phẩm (Chính)' },
      { value: 'model', label: '👤 Người mẫu' },
      { value: 'logo', label: '®️ Thương hiệu' },
      { value: 'background', label: '🏞️ Phông nền tham khảo' },
      { value: 'none', label: '🎨 Tham chiếu khác' },
  ];

  const hasProduct = formState.files.some(f => f.role === 'product');

  return (
    <div className="space-y-10 animate-fade-in">
      {/* Step 1: Upload Assets */}
      <div className="space-y-4">
          <div className="flex items-center justify-between">
              <label className="text-[12px] font-black text-slate-800 uppercase tracking-[0.15em] ml-1">
                Bước 1: Tải lên Sản phẩm/Mẫu
              </label>
              {!hasProduct && formState.files.length > 0 && (
                  <span className="text-[10px] font-black text-rose-600 animate-pulse bg-rose-50 px-2 py-1 rounded-md">Thiếu "Sản phẩm chính"</span>
              )}
          </div>
          <div className="bg-slate-50 border-2 border-dashed border-slate-300 rounded-[2.5rem] p-8 text-center cursor-pointer hover:border-red-400 hover:bg-red-50/30 transition-all group">
              <input type="file" id="file-upload" multiple accept="image/*" onChange={handleFileChange} className="sr-only" />
              <label htmlFor="file-upload" className="cursor-pointer">
                  <div className="w-14 h-14 bg-white rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-md group-hover:scale-110 transition-transform border border-slate-100">
                      <svg className="w-7 h-7 text-red-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12"/></svg>
                  </div>
                  <p className="text-[13px] font-extrabold text-slate-900 tracking-tight">Kéo thả ảnh thực tế hoặc <span className="text-red-600 underline">chọn tệp</span></p>
                  <p className="text-[11px] text-slate-500 font-bold mt-2 leading-relaxed px-4">AI sẽ trích xuất sản phẩm từ ảnh này để ghép vào bối cảnh Xuân 2026.</p>
              </label>
          </div>

          {formState.files.length > 0 && (
              <div className="grid grid-cols-1 gap-3">
                  {formState.files.map(file => (
                      <div key={file.id} className={`flex items-center gap-4 bg-white p-3 rounded-[1.5rem] border transition-all animate-fade-in ${file.role === 'product' ? 'border-red-200 shadow-lg ring-2 ring-red-50' : 'border-slate-200 shadow-sm'}`}>
                          <div className="relative">
                            <img src={`data:${file.mimeType};base64,${file.base64}`} className="w-14 h-14 object-cover rounded-xl border border-slate-100" />
                            {file.role === 'product' && <div className="absolute -top-1 -left-1 bg-red-600 text-white text-[8px] font-black px-1.5 py-0.5 rounded-full shadow-lg">STAR</div>}
                          </div>
                          <div className="flex-grow">
                              <select value={file.role} onChange={(e) => handleRoleChange(file.id, e.target.value as AdImageRole)}
                                  className={`w-full bg-slate-100 border-none text-[11px] font-black uppercase rounded-xl p-2.5 focus:ring-2 focus:ring-red-200 cursor-pointer transition-colors ${file.role === 'product' ? 'text-red-700' : 'text-slate-700'}`}>
                                  {roleOptions.map(opt => <option key={opt.value} value={opt.value}>{opt.label}</option>)}
                              </select>
                          </div>
                          <button type="button" onClick={() => handleRemoveFile(file.id)} className="p-2.5 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-xl transition-all">
                              <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M9 2a1 1 0 00-.894.553L7.382 4H4a1 1 0 000 2v10a2 2 0 002 2h8a2 2 0 002-2V6a1 1 0 100-2h-3.382l-.724-1.447A1 1 0 0011 2H9zM7 8a1 1 0 012 0v6a1 1 0 11-2 0V8zm4 0a1 1 0 012 0v6a1 1 0 11-2 0V8z" clipRule="evenodd"/></svg>
                          </button>
                      </div>
                  ))}
              </div>
          )}
      </div>

      {/* Step 2: Smart Idea Section */}
      <div className="bg-red-50/40 p-8 rounded-[2.5rem] border border-red-100/60 shadow-inner space-y-6">
        <div>
            <label className="text-[12px] font-black text-red-700 uppercase tracking-[0.15em] ml-1 mb-2 block">
              Bước 2: Gợi ý bối cảnh Xuân Bính Ngọ
            </label>
            <p className="text-[11px] text-slate-600 font-bold leading-relaxed">Nhập chủ đề hoặc phong cách bạn muốn (VD: "Phòng khách tết xưa", "Phong cách Neon Tết").</p>
        </div>

        <div className="flex flex-col gap-4">
            <div className="relative">
                <input 
                    type="text" 
                    value={suggestionQuery}
