export async function generateAdImage(formState: AdImageFormState): Promise<string[]> {
    const { files, prompt, variations } = formState;

    const generateSingle = async () => {
        // Reset parts for each variation to allow potential subtle differences
        const parts: any[] = [];

        // Add images with specific roles
        files.forEach(file => {
            parts.push({ 
                inlineData: { 
                    data: file.base64, 
                    mimeType: file.mimeType 
                } 
            });
            // Detailed role instruction for the model
            parts.push({ text: `This image is the ${file.role}. Keep its features, textures, and core appearance exactly as is.` });
        });

        // The technical prompt for composition
        parts.push({ text: `Task: Create a professional commercial image. 
Context: ${prompt}. 
Requirement: Seamlessly integrate the provided product into the scene. Match lighting, shadows, and perspective. The result should look like a high-end studio photograph.` });

        const res = await generateContentWithRetry({
            model: IMAGE_EDIT_MODEL,
            contents: { parts },
            config: { 
                systemInstruction: "Bạn là một chuyên gia nhiếp ảnh quảng cáo studio. Nhiệm vụ của bạn là ghép sản phẩm từ ảnh tải lên vào một bối cảnh mới một cách tự nhiên và chuyên nghiệp nhất, đảm bảo ánh sáng và đổ bóng hoàn hảo.",
                temperature: 1.0, // Higher temperature for variations
            },
        });

        const imagePart = res.candidates?.[0]?.content?.parts.find(p => p.inlineData);
        if (!imagePart?.inlineData?.data) throw new Error("AI không thể kết xuất hình ảnh từ dữ liệu được cung cấp.");
        return imagePart.inlineData.data;
    };

    try {
        // Run variations
        const results = [];
        for (let i = 0; i < variations; i++) {
            results.push(await generateSingle());
        }
        return results;
    } catch (error) {
        throw handleGeminiError(error, "tạo ảnh quảng cáo");
    }
}

