export async function generateAdImage(formState: AdImageFormState): Promise<string[]> {
    const { files, prompt, variations } = formState;

    const generateSingle = async () => {
        const parts: any[] = [];

        // Identity Preservation Hard-Constraints
        const identityInstruction = `
[IDENTITY PRESERVATION RULES]
1. Use the uploaded image as the main subject. 
2. Strictly preserve the original face identity. 
3. Do not change facial structure, eyes, nose, lips, skin texture. 
4. No face swap. No model replacement. 
5. Face accuracy priority: extremely high. 
6. Only modify outfit, hairstyle, background and lighting. 
7. Keep natural Vietnamese facial features. 
8. Ultra realistic, high detail skin texture.`;

        // Add images with specific roles
        files.forEach(file => {
            parts.push({ 
                inlineData: { 
                    data: file.base64, 
                    mimeType: file.mimeType 
                } 
            });
            parts.push({ text: `Main Subject Reference: This image is the ${file.role}. Follow the [IDENTITY PRESERVATION RULES] strictly for this subject.` });
        });

        // The technical prompt for composition
        parts.push({ text: `Task: Create a professional commercial image. 
Context: ${prompt}. 
${identityInstruction}
Requirement: Seamlessly integrate the subject into the scene. Match lighting, shadows, and perspective while keeping the face 100% original.` });

        const res = await generateContentWithRetry({
            model: IMAGE_EDIT_MODEL,
            contents: { parts },
            config: { 
                systemInstruction: "Bạn là một chuyên gia AI Image Editor hàng đầu. Nhiệm vụ quan trọng nhất của bạn là giữ nguyên diện mạo, khuôn mặt và đặc điểm nhận dạng của người trong ảnh. Tuyệt đối không thay đổi cấu trúc khuôn mặt (No face swap). Chỉ thay đổi trang phục, bối cảnh và ánh sáng theo mô tả.",
                temperature: 0.7, // Lower temperature for more stability in identity
            },
        });

        const imagePart = res.candidates?.[0]?.content?.parts.find(p => p.inlineData);
        if (!imagePart?.inlineData?.data) throw new Error("AI không thể kết xuất hình ảnh từ dữ liệu được cung cấp.");
        return imagePart.inlineData.data;
    };

    try {
        const results = [];
        for (let i = 0; i < variations; i++) {
            results.push(await generateSingle());
        }
        return results;
    } catch (error) {
        throw handleGeminiError(error, "tạo ảnh quảng cáo");
    }
}

