import { GoogleGenAI, Type, GenerateContentResponse, Modality } from "@google/genai";
import type { StoryFormState, StoryGenerationResponse, ScriptFormState, ScenePrompt, ArticleData, AdImageFormState, AdSuggestion, AdImageFile, AdImageRole, AffiliateFormState, AffiliateScriptResult } from '../types';

const GEMINI_MODEL = "gemini-3-flash-preview"; 
const GEMINI_PRO_MODEL = "gemini-3-pro-preview";
const IMAGE_GEN_MODEL = "imagen-4.0-generate-001";
// Nâng cấp lên Pro model cho chất lượng cao nhất và độ chính xác khuôn mặt
const IMAGE_EDIT_MODEL = "gemini-3-pro-image-preview"; 
const VEO_MODEL = "veo-3.1-fast-generate-preview";

// Hàm khởi tạo instance mới để đảm bảo lấy API Key mới nhất từ window.aistudio
const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

async function generateContentWithRetry(
    params: { model: string; contents: any; config?: any; },
    maxRetries = 2,
    initialDelay = 1000
): Promise<GenerateContentResponse> {
    let attempt = 0;
    while (attempt < maxRetries) {
        try {
            const ai = getAI();
            const response = await ai.models.generateContent(params);
            return response;
        } catch (error: any) {
            console.error("API Error:", error);
            // Nếu lỗi Quota (429) hoặc không tìm thấy (thường do key), ném lỗi đặc biệt để UI xử lý
            if (error?.message?.includes("429") || error?.message?.includes("RESOURCE_EXHAUSTED") || error?.message?.includes("404")) {
                throw new Error("QUOTA_EXCEEDED");
            }
            attempt++;
            if (attempt >= maxRetries) throw error;
            await new Promise(resolve => setTimeout(resolve, initialDelay * attempt));
        }
    }
    throw new Error("Failed after retries");
}

async function generateImagesWithRetry(
    params: { model: string; prompt: string; config?: any; },
    maxRetries = 2
): Promise<{ generatedImages: { image: { imageBytes: string } }[] }> {
    let attempt = 0;
    while (attempt < maxRetries) {
        try {
            const ai = getAI();
            return await ai.models.generateImages(params);
        } catch (error: any) {
            if (error?.message?.includes("429") || error?.message?.includes("RESOURCE_EXHAUSTED")) {
                throw new Error("QUOTA_EXCEEDED");
            }
            attempt++;
            if (attempt >= maxRetries) throw error;
            await new Promise(resolve => setTimeout(resolve, 2000));
        }
    }
    throw new Error("Image gen failed");
}

function handleGeminiError(error: unknown, context: string): Error {
    const msg = error instanceof Error ? error.message : String(error);
    if (msg === "QUOTA_EXCEEDED") {
        return new Error("Hạn mức (Quota) của API Key hiện tại đã hết. Vui lòng chọn/đổi API Key trả phí (Paid Project) để tiếp tục sử dụng dịch vụ chuyên nghiệp.");
    }
    return new Error(`Lỗi ${context}: ${msg}`);
}

const parseJsonResponse = <T>(responseText: string, context: string): T => {
    try {
        const cleanJson = responseText.trim().replace(/^```json/, '').replace(/```$/, '');
        return JSON.parse(cleanJson) as T;
    } catch (e) {
        throw new Error(`AI response for ${context} is not valid JSON`);
    }
};

