export async function generateAdImage(formState: AdImageFormState): Promise<string[]> {
    const { files, prompt, variations } = formState;

    const generateSingle = async () => {
        const parts: any[] = [];

        const identityInstruction = `
[STRICT IDENTITY PRESERVATION]
1. Subject: Use the person in the provided image as the ONLY subject.
2. Facial Structure: KEEP 100% ORIGINAL. No changes to eyes, nose, lips, or facial proportions.
3. Skin: Ultra-realistic 8K skin texture. No smoothing that hides details.
4. Vietnamese Features: Preserve the natural ethnic appearance.
5. No Face Swap: Do not replace the head or face with another model.
6. Transformation: ONLY change clothing, hairstyle (minimal), environment, and professional studio lighting.`;

        files.forEach(file => {
            parts.push({ 
                inlineData: { 
                    data: file.base64, 
                    mimeType: file.mimeType 
                } 
            });
            parts.push({ text: `Source Identity (${file.role}): Apply [STRICT IDENTITY PRESERVATION] to this person.` });
        });

        parts.push({ text: `Creative Concept: ${prompt}. Cinematic lighting, 8k resolution, photorealistic commercial photography.` });

        const res = await generateContentWithRetry({
            model: IMAGE_EDIT_MODEL,
            contents: { parts },
            config: { 
                imageConfig: {
                    aspectRatio: "1:1",
                    imageSize: "2K"
                },
                tools: [{googleSearch: {}}] // Pro model supports search for trending visual concepts
            },
        });

        const imagePart = res.candidates?.[0]?.content?.parts.find(p => p.inlineData);
        if (!imagePart?.inlineData?.data) throw new Error("AI không thể kết xuất hình ảnh.");
        return imagePart.inlineData.data;
    };

    try {
        const results = [];
        for (let i = 0; i < variations; i++) {
            results.push(await generateSingle());
        }
        return results;
    } catch (error) {
        throw handleGeminiError(error, "tạo ảnh quảng cáo");
    }
}

