// Hàm khởi tạo instance mới để đảm bảo lấy API Key mới nhất từ window.aistudio
const getAI = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("MISSING_API_KEY");
  return new GoogleGenAI({ apiKey });
};

// Robust content generation with retry logic
async function generateContentWithRetry(
    params: { model: string; contents: any; config?: any; },
    maxRetries = 2,
    initialDelay = 1000
): Promise<GenerateContentResponse> {
    let attempt = 0;
    while (attempt < maxRetries) {
        try {
            const ai = getAI();
            const response = await ai.models.generateContent(params);
            return response;
        } catch (error: any) {
            console.error("API Error Debug:", error);
            const errorMsg = error?.message || "";
            const statusCode = error?.status || "";

            // Xử lý lỗi hết hạn mức hoặc lỗi quyền truy cập
            if (errorMsg.includes("429") || errorMsg.includes("RESOURCE_EXHAUSTED")) {
                throw new Error("QUOTA_EXCEEDED");
            }
            // Lỗi 403: Quyền truy cập bị từ chối (Thường do Key không thuộc dự án trả phí cho các model Pro/Image)
            if (errorMsg.includes("403") || errorMsg.includes("PERMISSION_DENIED") || statusCode === "PERMISSION_DENIED") {
                throw new Error("PERMISSION_DENIED");
            }
            if (errorMsg.includes("404")) {
                throw new Error("MODEL_NOT_FOUND");
            }

            attempt++;
            if (attempt >= maxRetries) throw error;
            await new Promise(resolve => setTimeout(resolve, initialDelay * attempt));
        }
    }
    throw new Error("Failed after retries");
}

// Image generation with retry logic for Imagen models
async function generateImagesWithRetry(
    params: { model: string; prompt: string; config?: any; },
    maxRetries = 2
): Promise<{ generatedImages: { image: { imageBytes: string } }[] }> {
    let attempt = 0;
    while (attempt < maxRetries) {
        try {
            const ai = getAI();
            return await ai.models.generateImages(params);
        } catch (error: any) {
            const errorMsg = error?.message || "";
            if (errorMsg.includes("429") || errorMsg.includes("RESOURCE_EXHAUSTED")) {
                throw new Error("QUOTA_EXCEEDED");
            }
            if (errorMsg.includes("403") || errorMsg.includes("PERMISSION_DENIED")) {
                throw new Error("PERMISSION_DENIED");
            }
            attempt++;
            if (attempt >= maxRetries) throw error;
            await new Promise(resolve => setTimeout(resolve, 2000));
        }
    }
    throw new Error("Image gen failed");
}

// Centralized error handling for Gemini API
function handleGeminiError(error: unknown, context: string): Error {
    const msg = error instanceof Error ? error.message : String(error);

    if (msg === "MISSING_API_KEY") {
        return new Error("Chưa tìm thấy API Key. Vui lòng bấm vào nút 'QUẢN LÝ API KEY' phía trên để thiết lập.");
    }
    if (msg === "QUOTA_EXCEEDED") {
        return new Error("Hạn mức (Quota) của API Key hiện tại đã hết. Vui lòng sử dụng API Key trả phí (Paid Project) để tiếp tục.");
    }
    if (msg === "PERMISSION_DENIED") {
        return new Error("Truy cập bị từ chối (403 PERMISSION_DENIED). Các model AI cao cấp (Pro/Image) yêu cầu API Key từ một Google Cloud Project đã bật Billing (thanh toán). Vui lòng chọn API Key từ dự án trả phí để tiếp tục.");
    }
    if (msg === "MODEL_NOT_FOUND") {
        return new Error("Model không khả dụng hoặc API Key không hợp lệ. Vui lòng kiểm tra lại cấu hình API.");
    }

    return new Error(`Lỗi ${context}: ${msg}`);
}

// JSON parsing utility for AI responses
const parseJsonResponse = <T>(responseText: string, context: string): T => {
    try {
        const cleanJson = responseText.trim().replace(/^```json/, '').replace(/```$/, '');
        return JSON.parse(cleanJson) as T;
    } catch (e) {
        throw new Error(`AI response for ${context} không đúng định dạng JSON`);
    }
};

// Image background removal using Gemini 3 Pro
export async function removeBackground(file: AdImageFile): Promise<string> {
    const parts = [
      { inlineData: { data: file.base64, mimeType: file.mimeType } },
      { text: "Remove the background of this image. Keep original edges sharp. Output only image data." }
    ];
    try {
        const res = await generateContentWithRetry({
            model: IMAGE_EDIT_MODEL,
            contents: { parts },
            config: { imageConfig: { aspectRatio: "1:1" } }
        });
        const imagePart = res.candidates?.[0]?.content?.parts.find(p => p.inlineData);
        if (!imagePart?.inlineData?.data) throw new Error("AI không thể thực hiện tách nền.");
        return imagePart.inlineData.data;
    } catch (error) {
        throw handleGeminiError(error, "tách nền ảnh");
    }
}

