// Ad image generation using high-quality Gemini 3 Pro model
export async function generateAdImage(formState: AdImageFormState): Promise<string[]> {
    const { files, prompt, variations } = formState;

    const generateSingle = async () => {
        const parts: any[] = [];
        const identityInstruction = `
[STRICT IDENTITY PRESERVATION]
- Use the person's face from the uploaded image.
- DO NOT CHANGE eyes, nose, lips, or face shape.
- 100% identity accuracy required.
- Change only outfit, background, and lighting.`;

        files.forEach(file => {
            parts.push({ inlineData: { data: file.base64, mimeType: file.mimeType } });
            parts.push({ text: `Source for ${file.role}. Follow [STRICT IDENTITY PRESERVATION].` });
        });

        parts.push({ text: `Scene: ${prompt}. Photorealistic, 8k, professional studio lighting.` });

        const res = await generateContentWithRetry({
            model: IMAGE_EDIT_MODEL,
            contents: { parts },
            config: { 
                imageConfig: { aspectRatio: "1:1", imageSize: "2K" }
            },
        });

        const imagePart = res.candidates?.[0]?.content?.parts.find(p => p.inlineData);
        if (!imagePart?.inlineData?.data) throw new Error("AI không thể kết xuất hình ảnh.");
        return imagePart.inlineData.data;
    };

    try {
        const results = [];
        for (let i = 0; i < variations; i++) {
            results.push(await generateSingle());
        }
        return results;
    } catch (error) {
        throw handleGeminiError(error, "tạo ảnh quảng cáo");
    }
}

